challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "UPF is the source of the anomalous GTP traffic and media packet loss.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "The gauges for the UPF will show an extremely high packet_loss_ratio and/or anomalously high packet rates.",
          "falsifying_observation": "The UPF gauges show normal packet loss and traffic rates, while other components (like rtpengine) show high loss.",
          "conflates_with": []
        },
        {
          "tool": "get_diagnostic_metrics",
          "args_hint": "nf=upf. Look for metrics related to GTP packet processing, specifically error counters like 'gtpu_error_indications_rx' or 'gtpu_error_indications_tx'.",
          "expected_if_hypothesis_holds": "A significant and rising value for GTP error counters on the UPF.",
          "falsifying_observation": "GTP error counters on the UPF are zero or not increasing.",
          "conflates_with": []
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from='nr_gnb', to_ip=<UPF N3 interface IP>",
          "expected_if_hypothesis_holds": "High packet loss and/or RTT, indicating the UPF is failing to respond to traffic correctly.",
          "falsifying_observation": "Low packet loss and normal RTT. This would not be conclusive on its own but would contradict the partner probe's result if the fault lies with the UPF.",
          "conflates_with": [
            "The nr_gnb is the source of the problem.",
            "The network path between nr_gnb and upf is the source of the loss."
          ]
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from='smf', to_ip=<UPF N4 interface IP>",
          "expected_if_hypothesis_holds": "High packet loss and/or RTT. If the UPF is failing internally, it may affect both N3 and N4 interfaces.",
          "falsifying_observation": "Low packet loss and normal RTT. If the N3 ping fails but the N4 ping succeeds, it suggests the fault is localized to the UPF's N3 handling, not a full UPF failure.",
          "conflates_with": []
        }
      ],
      "notes": "This plan tests if the UPF itself is the source of the data plane failure observed during the 'vonr_call_setup' flow. Probes compare UPF's own data plane metrics against its control plane interface health."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "The gNB is the source of anomalous traffic causing downstream effects in the UPF and RTPEngine.",
      "primary_suspect_nf": "nr_gnb",
      "probes": [
        {
          "tool": "get_diagnostic_metrics",
          "args_hint": "nf=nr_gnb. Compare gNB's transmitted GTP packets ('gtp_pdu_tx_pkts') with UPF's received GTP packets ('gtpu_packets_in' on N3).",
          "expected_if_hypothesis_holds": "The number of packets sent by gNB is anomalously high and roughly equals the number of packets received by UPF.",
          "falsifying_observation": "The number of packets received by the UPF is significantly higher than the number sent by the gNB, proving the gNB is not the source of the traffic anomaly.",
          "conflates_with": []
        },
        {
          "tool": "get_network_status",
          "args_hint": "container=nr_gnb",
          "expected_if_hypothesis_holds": "The nr_gnb container is in a 'running' state.",
          "falsifying_observation": "The nr_gnb container is in an 'exited' or other non-running state, indicating a different failure mode.",
          "conflates_with": []
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from='amf', to_ip=<gNB N2 interface IP>",
          "expected_if_hypothesis_holds": "High packet loss or RTT, suggesting the gNB is overloaded or unresponsive.",
          "falsifying_observation": "Low packet loss and normal RTT, suggesting the gNB's control plane is healthy and responsive.",
          "conflates_with": [
            "The amf is the source of the problem.",
            "The network path between amf and nr_gnb is the source of the loss."
          ]
        }
      ],
      "notes": "This plan tests if the gNB is the origin of the traffic storm. The key probe compares gNB's outbound traffic counters with UPF's inbound counters to see if the UPF is merely forwarding anomalous traffic or generating it."
    },
    {
      "hypothesis_id": "h3",
      "hypothesis_statement": "rtpengine is the source of the anomalous packet loss ratio.",
      "primary_suspect_nf": "rtpengine",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "The 'rtpengine' gauges show a very high packet_loss_ratio, while the 'upf' gauges show a normal/low packet_loss_ratio.",
          "falsifying_observation": "The 'upf' gauges also show a very high packet_loss_ratio, similar to what 'rtpengine' is reporting. This would prove the loss occurred upstream of rtpengine.",
          "conflates_with": []
        },
        {
          "tool": "get_diagnostic_metrics",
          "args_hint": "nf=rtpengine. Look for internal error counters or a mismatch between packets received and packets sent.",
          "expected_if_hypothesis_holds": "A high value for an internal error counter, or a large, unexplained mismatch between received and sent packets.",
          "falsifying_observation": "Internal error counters are zero and packet counts are balanced, suggesting rtpengine is processing media streams correctly.",
          "conflates_with": []
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from='pcscf', to_ip=<rtpengine IP>",
          "expected_if_hypothesis_holds": "High packet loss or RTT, suggesting rtpengine is unresponsive.",
          "falsifying_observation": "Low packet loss and normal RTT, indicating rtpengine is reachable and responsive to network probes.",
          "conflates_with": [
            "The pcscf is the source of the problem.",
            "The network path between pcscf and rtpengine is the source of the loss."
          ]
        }
      ],
      "notes": "This plan aims to determine if rtpengine is the component creating the packet loss or merely reporting loss from an upstream component (like the UPF). The key probe compares data plane quality metrics from both UPF and rtpengine."
    }
  ]
}

